    #define CFF2_BUFSIZE 1024
    unsigned char cff2_data[CFF2_BUFSIZE];
    size_t cff2_len = 0;

    #define W1(b)  cff2_data[cff2_len++] = (b)
    #define W2(val) do { \
        cff2_data[cff2_len++] = ((val) >> 8) & 0xFF; \
        cff2_data[cff2_len++] = (val) & 0xFF; \
