    #define W3(val) do { \
        cff2_data[cff2_len++] = ((val) >> 16) & 0xFF; \
        cff2_data[cff2_len++] = ((val) >> 8) & 0xFF; \
        cff2_data[cff2_len++] = (val) & 0xFF; \
    } while(0)

