    size_t charstringsOffsetPos = cff2_len;
    W3(0x00);   /* placeholder */
    W1(0x1C); W1(0x11);   /* CharStrings operator */

    size_t topDictEnd = cff2_len;
    size_t topDictLength = topDictEnd - topDictStart;

    /* CharStrings INDEX */
    size_t charstringsStart = cff2_len;
    W2(1);      /* count = 1 */
    W1(1);      /* offSize = 1 */
    W1(1);      /* offset[0] = 1 */
    W1(2);      /* offset[1] = 2 */
    W1(0x0D);   /* endchar */

    /* VarStore data */
    size_t varStoreStart = cff2_len;
    /* version = 1.0 (fixed 16.16: 0x00010000) */
    W2(0x00); W2(0x01); W2(0x00); W2(0x00);
    W1(0x00);   /* format (0 = array) */
    W2(1);      /* dataCount = 1 */
    W2(18);     /* dataOffset = 18 */
    W2(1);      /* axisCount = 1 */
    W2(1);      /* regionCount = 1 */
    W2(0);      /* axis = 0 */
    W2(0);      /* start = 0.0 (16.16) */
    W2(0x40); W2(0x00);   /* end = 1.0 (16.16) */
    W2(0);      /* varDataCount = 0 */
    W2(1);      /* regionIndicesCount = 1 */
    W2(0);      /* regionIndices[0] = 0 */

