    W1(0x1C); W2(0x01);
    W1(0x1C); W2(0x01);
    W1(0x1C); W2(0x01);
    W1(0x1C); W2(0x01);
    W1(0x1C); W2(0x02);
    W1(0x1C); W1(0x17);   /* blend operator */
    /* Second blend: same */
    W1(0x1C); W2(0x01);
    W1(0x1C); W2(0x01);
    W1(0x1C); W2(0x01);
    W1(0x1C); W2(0x01);
    W1(0x1C); W2(0x02);
    W1(0x1C); W1(0x17);
    /* Third blend: will read stale parser->stack entries */
