    cff2_data[varStoreOffsetPos+1] = (varStoreStart >> 8) & 0xFF;
    cff2_data[varStoreOffsetPos+2] = varStoreStart & 0xFF;

    /* Private size */
    cff2_data[privateSizePos]   = (privateSize >> 16) & 0xFF;
    cff2_data[privateSizePos+1] = (privateSize >> 8) & 0xFF;
    cff2_data[privateSizePos+2] = privateSize & 0xFF;

    /* Private offset */
    cff2_data[privateOffsetPos]   = (privateStart >> 16) & 0xFF;
    cff2_data[privateOffsetPos+1] = (privateStart >> 8) & 0xFF;
    cff2_data[privateOffsetPos+2] = privateStart & 0xFF;

    /* CharStrings offset */
    cff2_data[charstringsOffsetPos]   = (charstringsStart >> 16) & 0xFF;
    cff2_data[charstringsOffsetPos+1] = (charstringsStart >> 8) & 0xFF;
    cff2_data[charstringsOffsetPos+2] = charstringsStart & 0xFF;

    /* --- Now write the OpenType container --- */
    /* OTF Header: 12 bytes */
    unsigned char sfVersion[4] = {0x00, 0x01, 0x00, 0x00};  /* 0x00010000 */
    fwrite(sfVersion, 1, 4, f);

    unsigned short numTables = 1;
    unsigned short searchRange = 0;    /* not used by FreeType? We'll set to 0 */
    unsigned short entrySelector = 0;
    unsigned short rangeShift = 0;

    fwrite(&numTables, 2, 1, f);
    fwrite(&searchRange, 2, 1, f);
    fwrite(&entrySelector, 2, 1, f);
    fwrite(&rangeShift, 2, 1, f);

    /* Table directory entry for 'CFF2' (16 bytes) */
    unsigned char tag[4] = {'C', 'F', 'F', '2'};
    fwrite(tag, 1, 4, f);

    unsigned long checksum = 0;   /* FreeType doesn't verify checksums */
    fwrite(&checksum, 4, 1, f);

    unsigned long offset = 12 + 16;  /* header + table directory = 28 */
    fwrite(&offset, 4, 1, f);

    unsigned long length = (unsigned long)cff2_len;
    fwrite(&length, 4, 1, f);

    /* Now write the CFF2 data at the correct file position */
    fseek(f, offset, SEEK_SET);
    fwrite(cff2_data, 1, cff2_len, f);

